import * as t from "io-ts";
import { RecipientEntry } from "./recipientEntry";
import { WithdrawIntent } from "./withdrawIntent";

/**
 * @title Near Withdraw Intent
 */
export const NearWithdrawIntent = t.intersection([
  WithdrawIntent,
  t.type({
    recipients: t.array(RecipientEntry),
  }),
]);

export type NearWithdrawIntent = t.TypeOf<typeof NearWithdrawIntent>;
